import React, { useState, useContext, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { AuthContext } from '../App';
import { API_URL } from '../config';

const EXERCISE_LIBRARY = {
  '胸部 (Chest)': ['杠铃卧推', '上斜哑铃推举', '哑铃飞鸟', '俯卧撑', '绳索夹胸', '下斜哑铃推举'],
  '背部 (Back)': ['引体向上', '高位下拉', '杠铃划船', '硬拉', '坐姿划船', 'T型划船'],
  '腿部 (Legs)': ['深蹲', '腿举', '罗马尼亚硬拉', '腿屈伸', '提踵', '保加利亚分腿蹲', '哈克深蹲'],
  '肩部 (Shoulders)': ['杠铃推举', '哑铃侧平举', '哑铃前平举', '绳索面拉', '阿诺德推举'],
  '手臂 (Arms)': ['杠铃弯举', '哑铃弯举', '三头下压', '仰卧臂屈伸', '锤式弯举', '绳索弯举'],
  '核心 (Core)': ['卷腹', '平板支撑', '悬垂举腿', '俄罗斯挺身', '侧平板', '山地爬行'],
  '有氧 (Cardio)': ['跑步', '椭圆机', '动感单车', '划船机', '跳绳', '游泳', '爬楼梯'],
};

const CARDIO_CATEGORY = '有氧 (Cardio)';

// 判断某个动作是否属于有氧（基于库分类，比关键词更准确）
const isCardioExercise = (exercise, category) => {
  if (category === CARDIO_CATEGORY) return true;
  if (category === 'Custom') {
    // 自定义动作：仍用关键词兜底
    return ['跑', '骑', '椭圆', '划船', '跳绳', '有氧', '游泳'].some(kw => exercise.includes(kw));
  }
  return false;
};

const Stepper = ({ value, onChange, min = 0, step = 1, label, isWeightField }) => {
  const val = parseFloat(value) || 0;
  const displayValue = (isWeightField && val === 0) ? '自重' : value;
  const isBodyweight = (isWeightField && val === 0);

  return (
    <div style={{ display: 'flex', flexDirection: 'column', flex: 1 }}>
      <span style={{ fontSize: 12, color: 'var(--apple-text-secondary)', marginBottom: 4, textAlign: 'center' }}>
        {isBodyweight ? '重量 (自重)' : label}
      </span>
      <div className="stepper-input">
        <div className="stepper-btn" onClick={() => onChange(Math.max(min, val - step))}>-</div>
        <input
          type={isBodyweight ? 'text' : 'number'}
          value={displayValue}
          onChange={e => {
            if (e.target.value === '自重') onChange(0);
            else onChange(e.target.value);
          }}
          placeholder="0"
          style={{ color: isBodyweight ? 'var(--apple-blue)' : 'inherit', fontSize: isBodyweight ? 16 : 18 }}
        />
        <div className="stepper-btn" onClick={() => onChange(val + step)}>+</div>
      </div>
    </div>
  );
};

const AddWorkout = () => {
  const { token } = useContext(AuthContext);
  const navigate = useNavigate();
  const [step, setStep] = useState(1);

  // Form state
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [exercise, setExercise] = useState('');
  const [exerciseType, setExerciseType] = useState('strength'); // 'strength' | 'cardio'
  const [customExercise, setCustomExercise] = useState('');
  const [sets, setSets] = useState([{ weight: '', reps: '' }]);
  const [notes, setNotes] = useState('');

  // UI state
  const [activeCategory, setActiveCategory] = useState('胸部 (Chest)');
  const [isLoadingHistory, setIsLoadingHistory] = useState(false);

  // Rest timer
  const [timerDuration, setTimerDuration] = useState(0);
  const [timerActive, setTimerActive] = useState(false);

  useEffect(() => {
    let interval = null;
    if (timerActive && timerDuration > 0) {
      interval = setInterval(() => setTimerDuration(prev => prev - 1), 1000);
    } else if (timerDuration <= 0 && timerActive) {
      setTimerActive(false);
      if (window.navigator?.vibrate) window.navigator.vibrate(500);
    }
    return () => clearInterval(interval);
  }, [timerActive, timerDuration]);

  const startTimer = (seconds) => {
    setTimerDuration(seconds);
    setTimerActive(true);
  };

  const formatTime = (s) =>
    `${Math.floor(s / 60).toString().padStart(2, '0')}:${(s % 60).toString().padStart(2, '0')}`;

  const handleExerciseSelect = async (selectedEx, category) => {
    setExercise(selectedEx);
    const cardio = isCardioExercise(selectedEx, category);
    setExerciseType(cardio ? 'cardio' : 'strength');
    setIsLoadingHistory(true);

    if (cardio) {
      setSets([{ weight: 30, reps: 300 }]);
    } else {
      try {
        const res = await fetch(`${API_URL}/api/workouts/last/${encodeURIComponent(selectedEx)}`, {
          headers: { 'x-auth-token': token },
        });
        if (res.ok) {
          const last = await res.json();
          if (last?.sets?.length > 0) {
            setSets(last.sets.map(s => ({ weight: s.weight, reps: s.reps })));
          } else {
            setSets([{ weight: 0, reps: 0 }]);
          }
        }
      } catch {
        setSets([{ weight: 0, reps: 0 }]);
      }
    }

    setIsLoadingHistory(false);
    setStep(2);
  };

  const handleSetChange = (index, field, value) => {
    const newSets = [...sets];
    newSets[index][field] = value;
    setSets(newSets);
  };

  const addSet = () => {
    // 复制最后一组的重量，次数清空（更符合训练习惯）
    const lastSet = sets[sets.length - 1];
    setSets([...sets, { weight: lastSet.weight, reps: lastSet.reps }]);
  };

  const removeSet = (index) => {
    if (sets.length > 1) setSets(sets.filter((_, i) => i !== index));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    let validSets;
    if (exerciseType === 'cardio') {
      // 有氧：时长(weight)可以为0但reps(卡路里)需要有值，或者只要有时长
      validSets = sets.map(s => ({
        weight: parseFloat(s.weight) || 0,
        reps: parseInt(s.reps) || 0,
      })).filter(s => s.weight > 0);
    } else {
      // 力量：自重(weight=0)是合法的，reps必须有值
      validSets = sets.map(s => ({
        weight: parseFloat(s.weight) || 0,
        reps: parseInt(s.reps) || 0,
      })).filter(s => s.reps > 0); // 只要次数>0就合法（包含自重训练）
    }

    if (validSets.length === 0) {
      alert('请至少添加一组有效的训练数据。');
      return;
    }

    try {
      const res = await fetch(`${API_URL}/api/workouts`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'x-auth-token': token },
        body: JSON.stringify({ date, exercise, type: exerciseType, sets: validSets, notes }),
      });
      if (res.ok) {
        navigate('/');
      } else {
        alert('添加训练失败，请重试。');
      }
    } catch {
      alert('服务器错误，请稍后再试。');
    }
  };

  // ========== 步骤1：选择动作 ==========
  if (step === 1) {
    return (
      <div className="form-container" style={{ maxWidth: 600, marginTop: 80, padding: 30 }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}>
          <h2 style={{ margin: 0 }}>选择动作</h2>
          <button className="secondary" onClick={() => navigate('/')} style={{ padding: '8px 16px', fontSize: 14 }}>
            取消
          </button>
        </div>

        <div className="category-pills" style={{ paddingBottom: 15 }}>
          {Object.keys(EXERCISE_LIBRARY).map(cat => (
            <div
              key={cat}
              className={`category-pill ${activeCategory === cat ? 'active' : ''}`}
              onClick={() => setActiveCategory(cat)}
            >
              {cat}
            </div>
          ))}
          <div
            className={`category-pill ${activeCategory === 'Custom' ? 'active' : ''}`}
            style={{ border: '1px dashed var(--apple-blue)', color: activeCategory === 'Custom' ? 'white' : 'var(--apple-blue)' }}
            onClick={() => setActiveCategory('Custom')}
          >
            + 自定义
          </div>
        </div>

        {activeCategory !== 'Custom' ? (
          <div className="exercise-list">
            {EXERCISE_LIBRARY[activeCategory].map(ex => (
              <div
                key={ex}
                className="exercise-option"
                onClick={() => handleExerciseSelect(ex, activeCategory)}
              >
                <span>{activeCategory === CARDIO_CATEGORY ? '🏃 ' : '🏋️ '}{ex}</span>
                {isLoadingHistory && exercise === ex && (
                  <span style={{ color: 'var(--apple-text-secondary)', fontSize: 13 }}>加载中...</span>
                )}
              </div>
            ))}
          </div>
        ) : (
          <div style={{ textAlign: 'left', marginTop: 20 }}>
            <label>动作名称</label>
            <input
              type="text"
              placeholder="例如：保加利亚分腿蹲"
              value={customExercise}
              onChange={e => setCustomExercise(e.target.value)}
              onKeyDown={e => {
                if (e.key === 'Enter' && customExercise.trim()) {
                  handleExerciseSelect(customExercise.trim(), 'Custom');
                }
              }}
            />
            <div style={{ display: 'flex', gap: 10 }}>
              <button
                style={{ flex: 1 }}
                disabled={!customExercise.trim()}
                onClick={() => handleExerciseSelect(customExercise.trim(), 'Custom')}
              >
                力量训练
              </button>
              <button
                className="secondary"
                style={{ flex: 1, background: 'rgba(255,149,0,0.1)', color: '#d87000', border: '1px solid rgba(255,149,0,0.3)' }}
                disabled={!customExercise.trim()}
                onClick={() => {
                  setExerciseType('cardio');
                  handleExerciseSelect(customExercise.trim(), 'Custom');
                }}
              >
                有氧训练
              </button>
            </div>
          </div>
        )}
      </div>
    );
  }

  // ========== 步骤2：记录组数 ==========
  const isCardio = exerciseType === 'cardio';

  return (
    <div className="form-container" style={{ maxWidth: 600, marginTop: 80, padding: 30 }}>
      <div style={{ display: 'flex', alignItems: 'center', marginBottom: 20 }}>
        <button
          className="secondary"
          onClick={() => setStep(1)}
          style={{ padding: '8px 16px', marginRight: 15, borderRadius: 12 }}
        >
          ← 返回
        </button>
        <div>
          <h2 style={{ margin: 0 }}>{exercise}</h2>
          <span style={{
            fontSize: 12,
            padding: '2px 8px',
            borderRadius: 6,
            background: isCardio ? 'rgba(255,149,0,0.1)' : 'rgba(0,113,227,0.1)',
            color: isCardio ? '#d87000' : 'var(--apple-blue)',
            fontWeight: 500,
          }}>
            {isCardio ? '有氧训练' : '力量训练'}
          </span>
        </div>
      </div>

      <form onSubmit={handleSubmit} style={{ textAlign: 'left' }}>
        <label>日期</label>
        <input type="date" value={date} onChange={e => setDate(e.target.value)} required style={{ marginBottom: 24 }} />

        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 }}>
          <label style={{ margin: 0 }}>{isCardio ? '时长与消耗' : '组数与次数'}</label>
          {isLoadingHistory && <span style={{ fontSize: 13, color: 'var(--apple-text-secondary)' }}>智能预填中...</span>}
        </div>

        {sets.map((set, index) => (
          <div key={index} className="set-row">
            {!isCardio && <div className="set-number">{index + 1}</div>}

            <Stepper
              label={isCardio ? '时长 (分钟)' : '重量 (kg)'}
              value={set.weight}
              step={isCardio ? 5 : 2.5}
              isWeightField={!isCardio}
              onChange={val => handleSetChange(index, 'weight', val)}
            />

            <Stepper
              label={isCardio ? '消耗 (大卡)' : '次数'}
              value={set.reps}
              step={isCardio ? 10 : 1}
              onChange={val => handleSetChange(index, 'reps', val)}
            />

            {sets.length > 1 && (
              <button
                type="button"
                className="secondary"
                style={{ width: 40, height: 40, padding: 0, borderRadius: 10, fontSize: 18, display: 'flex', alignItems: 'center', justifyContent: 'center' }}
                onClick={() => removeSet(index)}
              >
                ×
              </button>
            )}
          </div>
        ))}

        {!isCardio && (
          <button
            type="button"
            className="secondary"
            style={{ marginBottom: 10, width: '100%', background: 'rgba(0,113,227,0.08)', color: 'var(--apple-blue)', fontWeight: 600 }}
            onClick={addSet}
          >
            + 添加一组（复制上组重量）
          </button>
        )}

        {/* 休息计时器 */}
        {!isCardio && (
          <>
            <div style={{ marginBottom: 8, display: 'flex', alignItems: 'center' }}>
              <span style={{ fontSize: 13, color: 'var(--apple-text-secondary)', fontWeight: 500 }}>
                休息计时
              </span>
            </div>
            <div className="quick-timer-btns" style={{ marginBottom: 20 }}>
              <button type="button" onClick={() => startTimer(60)}>1:00</button>
              <button type="button" onClick={() => startTimer(90)}>1:30</button>
              <button type="button" onClick={() => startTimer(120)}>2:00</button>
              <button type="button" onClick={() => startTimer(180)}>3:00</button>
            </div>
          </>
        )}

        <label>备注（选填）</label>
        <textarea
          placeholder="今天的状态、心得或特别情况..."
          value={notes}
          onChange={e => setNotes(e.target.value)}
          rows={2}
          style={{ marginBottom: 24 }}
        />

        <button type="submit" style={{ width: '100%', fontSize: 17, padding: 16 }}>
          保存训练
        </button>
      </form>

      {/* 休息计时器悬浮条 */}
      {timerActive && (
        <div className="rest-timer-bar">
          <div className="timer-clock">⏳ {formatTime(timerDuration)}</div>
          <div className="timer-controls">
            <button type="button" onClick={() => setTimerDuration(prev => prev + 30)}>+30s</button>
            <button type="button" onClick={() => setTimerActive(false)}>结束</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default AddWorkout;
